const d = $input.item.json.body || $input.item.json;
const data = d.data || d;
const tier = data.reminderTier || 1;
const days = data.daysPending || 3;
const name = data.clientName || 'Estimado proveedor';

// Tono progresivo: amigable → firme → urgente
const themes = {
  1: { color: '#2563eb', bg: '#eff6ff', border: '#bfdbfe', text: '#1e40af', icon: '👋', greeting: '¡Hola', cta: 'Te agradeceríamos mucho si nos lo pudieras enviar.', subject: 'Recordatorio amigable' },
  2: { color: '#d97706', bg: '#fffbeb', border: '#fde68a', text: '#92400e', icon: '📌', greeting: 'Hola', cta: 'Necesitamos el complemento para poder cerrar el proceso contable.', subject: '2do recordatorio' },
  3: { color: '#dc2626', bg: '#fef2f2', border: '#fecaca', text: '#991b1b', icon: '🚨', greeting: 'Hola', cta: 'Es muy importante que nos envíes el complemento a la brevedad para evitar retrasos en el proceso.', subject: '3er recordatorio — Urgente' }
};
const t = themes[tier] || themes[1];

const html = `
<div style="font-family:'Segoe UI',Arial,sans-serif;max-width:580px;margin:0 auto;border:1px solid #e5e7eb;border-radius:12px;overflow:hidden">
  <div style="background:${t.color};padding:28px 24px;text-align:center">
    <p style="font-size:36px;margin:0">${t.icon}</p>
    <h1 style="color:#fff;margin:8px 0 0;font-size:20px;font-weight:600">${t.subject}</h1>
  </div>
  <div style="padding:32px 28px;background:#ffffff">
    <p style="color:#1f2937;font-size:16px;margin:0 0 16px">${t.greeting} <strong>${name}</strong>,</p>
    <p style="color:#4b5563;font-size:15px;line-height:1.7;margin:0 0 20px">Esperamos que estés bien. Te escribimos porque llevamos <strong>${days} días</strong> esperando el <strong>complemento de pago (REP)</strong> de una factura que ya fue liquidada.</p>
    <div style="background:${t.bg};border-left:4px solid ${t.color};padding:16px 20px;border-radius:0 8px 8px 0;margin:0 0 24px">
      <p style="color:${t.text};margin:0;font-size:14px;line-height:1.6">${t.cta}</p>
    </div>
    <div style="background:#f9fafb;border-radius:8px;padding:16px 20px;margin:0 0 24px">
      <p style="color:#6b7280;margin:0 0 4px;font-size:13px;font-weight:600;text-transform:uppercase;letter-spacing:0.5px">¿Cómo enviarlo?</p>
      <p style="color:#374151;margin:0;font-size:14px;line-height:1.6">Simplemente <strong>responde a este correo</strong> adjuntando el XML o PDF del complemento. Nosotros nos encargamos del resto.</p>
    </div>
    <p style="color:#6b7280;font-size:14px;line-height:1.6;margin:0">Cualquier duda estamos para ayudarte. ¡Gracias por tu atención!</p>
  </div>
  <div style="padding:20px 28px;background:#f9fafb;border-top:1px solid #e5e7eb;text-align:center">
    <p style="color:#9ca3af;font-size:12px;margin:0">Lolita — Equipo de Tesorería · <strong>Grupo Orsega</strong></p>
  </div>
</div>`;

return {
  json: {
    to: d.to || data.clientEmail,
    subject: d.subject || `${t.subject} — Complemento de Pago Pendiente`,
    html: html
  }
};
